import React from 'react';
import { View } from 'react-native';
import type {
  SDUIScreen,
  SDUIComponent,
  SDUIComponentRegistry,
  SDUIComponentProps,
  SDUIContext,
} from '../models';
import { interpolateDeep } from '../utils/interpolation';
import { getDefaultRegistry, getRenderer } from '../registry';
import FallbackComponent from './FallbackComponent';

interface ScreenRendererProps {
  screen: SDUIScreen;
  registry?: SDUIComponentRegistry;
  onAction?: (action: string, payload?: Record<string, unknown>) => void;
}

function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  index: number,
) {
  const interpolatedProps = interpolateDeep(
    component.props,
    context,
  ) as SDUIComponentProps;

  const Renderer = getRenderer(registry, component.type);

  if (!Renderer) {
    return (
      <FallbackComponent
        key={`fallback-${index}`}
        type={component.type}
        props={interpolatedProps}
        context={context}
      />
    );
  }

  return <Renderer key={`${component.type}-${index}`} props={interpolatedProps} context={context} />;
}

export default function ScreenRenderer({
  screen,
  registry,
}: ScreenRendererProps) {
  const activeRegistry = registry ?? getDefaultRegistry();
  const { context, header, body, footer } = screen;

  return (
    <View style={{ flex: 1 }}>
      {header && (
        <View>
          {renderComponent(header, context, activeRegistry, -1)}
        </View>
      )}

      <View style={{ flex: 1 }}>
        {body.map((component, index) =>
          renderComponent(component, context, activeRegistry, index),
        )}
      </View>

      {footer && (
        <View>
          {renderComponent(footer, context, activeRegistry, -2)}
        </View>
      )}
    </View>
  );
}

