import {
  createRegistry,
  registerComponent,
  getRenderer,
  getDefaultRegistry,
  registerToDefault,
} from './index';
import type { SDUIComponentRenderer } from '../models';

const MockComponent: SDUIComponentRenderer = () => null;
const AnotherComponent: SDUIComponentRenderer = () => null;

describe('SDUI Registry', () => {
  describe('createRegistry', () => {
    it('creates an empty registry', () => {
      const registry = createRegistry();
      expect(Object.keys(registry)).toHaveLength(0);
    });

    it('creates a registry with initial components', () => {
      const registry = createRegistry({ heading: MockComponent });
      expect(registry.heading).toBe(MockComponent);
    });
  });

  describe('registerComponent', () => {
    it('adds a component to the registry', () => {
      const registry = createRegistry();
      const updated = registerComponent(registry, 'button', MockComponent);
      expect(updated.button).toBe(MockComponent);
    });

    it('does not mutate the original registry', () => {
      const registry = createRegistry();
      registerComponent(registry, 'button', MockComponent);
      expect(registry.button).toBeUndefined();
    });

    it('overwrites an existing component', () => {
      const registry = createRegistry({ button: MockComponent });
      const updated = registerComponent(registry, 'button', AnotherComponent);
      expect(updated.button).toBe(AnotherComponent);
    });
  });

  describe('getRenderer', () => {
    it('returns the renderer for a registered type', () => {
      const registry = createRegistry({ heading: MockComponent });
      expect(getRenderer(registry, 'heading')).toBe(MockComponent);
    });

    it('returns undefined for an unregistered type', () => {
      const registry = createRegistry();
      expect(getRenderer(registry, 'unknown')).toBeUndefined();
    });
  });

  describe('default registry', () => {
    it('starts empty', () => {
      const registry = getDefaultRegistry();
      expect(typeof registry).toBe('object');
    });

    it('registerToDefault adds to the default registry', () => {
      registerToDefault('test_component', MockComponent);
      const registry = getDefaultRegistry();
      expect(registry.test_component).toBe(MockComponent);
    });
  });
});

