import React from 'react';
import { View, ScrollView } from 'react-native';
import { Text, Box, SeparatorHorizontal, Button } from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type {
  SDUIScreen,
  SDUIComponentProps,
  SDUIContext,
  SDUIComponentRenderer,
} from '../services/sdui/models';
import { createRegistry, registerComponent } from '../services/sdui/registry';
import { ScreenRenderer } from '../services/sdui/renderer';

const HeadingAdapter: SDUIComponentRenderer = ({ props }) => (
  <Text type="headingMDL" mb="smaller">
    {String(props.text ?? '')}
  </Text>
);

const TextAdapter: SDUIComponentRenderer = ({ props }) => (
  <Text type="bodyMD" mb="nano" color={props.color ? String(props.color) : undefined}>
    {String(props.text ?? '')}
  </Text>
);

const BalanceAdapter: SDUIComponentRenderer = ({ props }) => (
  <Box
    direction
    pd="squishSmall"
    bgColor="LIGHT_BASE_02"
    br="sm"
    mb="smaller"
    align="center"
  >
    <Box flex={1}>
      <Text type="bodySM" color="INTENSE_COLOR_03">
        {String(props.label ?? '')}
      </Text>
    </Box>
    <Box>
      <Text type="subtitleXXL">{String(props.points ?? '')}</Text>
      <Text type="bodySM" color="INTENSE_COLOR_03">
        {String(props.value ?? '')}
      </Text>
    </Box>
  </Box>
);

const ButtonAdapter: SDUIComponentRenderer = ({ props }) => (
  <Box mb="nano">
    <Button
      text={String(props.label ?? props.text ?? '')}
      onPress={() => {}}
    />
  </Box>
);

const LinkAdapter: SDUIComponentRenderer = ({ props }) => (
  <Box mb="nano">
    <Text type="bodyMD" color="BRAND_IDENTITY_01">
      {String(props.text ?? '')}
    </Text>
  </Box>
);

const SeparatorAdapter: SDUIComponentRenderer = () => (
  <SeparatorHorizontal
    mb="smaller"
    bgColor="BRAND_COMPLEMENT_02"
    height={1}
    width="100%"
  />
);

const NavHeaderAdapter: SDUIComponentRenderer = ({ props }) => (
  <Box pd="squishSmall" bgColor="BRAND_IDENTITY_01" mb="smaller">
    <Text type="subtitleXXL" color="LIGHT_BASE_01">
      {String(props.title ?? '')}
    </Text>
  </Box>
);

function buildDemoRegistry() {
  let registry = createRegistry();
  registry = registerComponent(registry, 'heading', HeadingAdapter);
  registry = registerComponent(registry, 'text', TextAdapter);
  registry = registerComponent(registry, 'balance_display', BalanceAdapter);
  registry = registerComponent(registry, 'button', ButtonAdapter);
  registry = registerComponent(registry, 'link', LinkAdapter);
  registry = registerComponent(registry, 'separator', SeparatorAdapter);
  registry = registerComponent(registry, 'nav_header', NavHeaderAdapter);
  return registry;
}

const MOCK_SCREEN: SDUIScreen = {
  id: 'voucher_form',
  context: {
    product: {
      key: 'abastecimento',
      name: 'Abastecimento',
    },
    balance: {
      points: 25720,
      pointsFormatted: '25.720',
      valueFormatted: 'R$ 7.716,00',
    },
  },
  header: {
    type: 'nav_header',
    props: { title: 'Voucher para {{product.name}}', showBack: true },
  },
  body: [
    {
      type: 'heading',
      props: { text: 'Defina o desconto para seu {{product.key}}' },
    },
    {
      type: 'balance_display',
      props: {
        label: 'Pontos disponíveis',
        points: '{{balance.pointsFormatted}}',
        value: '{{balance.valueFormatted}}',
      },
    },
    { type: 'separator', props: {} },
    {
      type: 'text',
      props: { text: 'Informe o valor em pontos ou reais que deseja converter.' },
    },
    {
      type: 'link',
      props: { text: 'Exibir regras de uso', to: 'app://voucher/rules' },
    },
    {
      type: 'unknown_widget',
      props: { demo: 'This shows fallback rendering' },
    },
  ],
  footer: {
    type: 'button',
    props: { label: 'Continuar' },
  },
};

function ScreenRendererDemo() {
  const registry = buildDemoRegistry();

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 600 }}>
        <Text type="headingMDL" mb="smaller">
          SDUI Screen Renderer — SP_0002.2
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Renders a complete screen from JSON using the component registry.
          Interpolation is applied automatically. Unknown types show a fallback.
        </Text>
        <SeparatorHorizontal
          mb="smaller"
          bgColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
        />

        <Text type="subtitleXXL" mb="nano">
          Rendered Screen
        </Text>
        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm" mb="smaller">
          <ScreenRenderer screen={MOCK_SCREEN} registry={registry} />
        </Box>

        <Text type="subtitleXXL" mb="nano">
          Source JSON (input)
        </Text>
        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <Text type="bodySM">
            {JSON.stringify(MOCK_SCREEN, null, 2)}
          </Text>
        </Box>
      </View>
    </ScrollView>
  );
}

const meta: Meta<typeof ScreenRendererDemo> = {
  title: 'SDUI/ScreenRenderer',
  component: ScreenRendererDemo,
};

export default meta;

type Story = StoryObj<typeof meta>;

export const Demo: Story = {};

